import { GoogleGenAI, Chat, GenerateContentResponse, Content, Tool, LiveServerMessage, Modality, Part } from "@google/genai";
import { 
  ASTRA_NORMAL_INSTRUCTION, 
  ASTRA_ROAST_INSTRUCTION, 
  ASTRA_SKULL_INSTRUCTION 
} from '../constants';
import { Attachment, GenerationMode, AstraMode, VoiceProfile, GroundingMetadata } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

let chatInstance: Chat | null = null;
let currentGenMode: GenerationMode = 'CHAT';
let currentModelId = 'gemini-3-pro-preview';
let ttsAudioContext: AudioContext | null = null;
let ttsSource: AudioBufferSourceNode | null = null;
let currentTtsRequestId = 0;

const getSystemPrompt = (astraMode: AstraMode) => {
    const now = new Date();
    const istTime = now.toLocaleString("en-IN", { timeZone: "Asia/Kolkata", dateStyle: "full", timeStyle: "medium" });
    const timeContext = `\n\n[SYNC]: ${istTime} | LOC: INDIA | ARCHITECT: AYUSH SINGH`;

    let instruction = "";
    switch(astraMode) {
        case 'roast': instruction = ASTRA_ROAST_INSTRUCTION; break;
        case 'skull': instruction = ASTRA_SKULL_INSTRUCTION; break;
        case 'normal': default: instruction = ASTRA_NORMAL_INSTRUCTION; break;
    }
    return instruction + timeContext;
};

const getModelConfig = (genMode: GenerationMode, astraMode: AstraMode) => {
  const systemInstruction = getSystemPrompt(astraMode);

  switch (genMode) {
    case 'DEEP_THINK':
      return {
        model: 'gemini-3-pro-preview',
        config: {
          systemInstruction,
          thinkingConfig: { thinkingBudget: 32768 }
        }
      };
    case 'WEB_INTEL':
      return {
        model: 'gemini-2.5-flash',
        config: {
          systemInstruction,
          tools: [{ googleSearch: {} } as Tool]
        }
      };
    case 'SPEED_RUN':
      return {
        model: 'gemini-2.5-flash',
        config: {
          systemInstruction,
          temperature: 0.7
        }
      };
    case 'ASTRA_CODER':
        return {
             model: 'gemini-3-pro-preview',
             config: { 
                 systemInstruction: "You are ASTRA CODER. Expert developer. Architect: Ayush Singh. Provide clean, production-ready code blocks.",
                 temperature: 0.2 
             }
        };
    case 'IMAGE_EDIT': 
        return {
            model: 'gemini-2.5-flash-image',
            config: { systemInstruction }
        };
    case 'ASTRA_DETECTION':
         return {
            model: 'gemini-3-pro-preview',
            config: { systemInstruction }
         };
    case 'CHAT':
    default:
      return {
        model: 'gemini-2.5-flash',
        config: {
          systemInstruction,
          temperature: astraMode === 'skull' ? 1.0 : 0.8,
        }
      };
  }
};

export const initializeChat = (
  genMode: GenerationMode = 'CHAT', 
  astraMode: AstraMode = 'normal',
  history?: Content[]
) => {
  const { model, config } = getModelConfig(genMode, astraMode);
  currentModelId = model;
  currentGenMode = genMode;

  chatInstance = ai.chats.create({
    model: model,
    config: config,
    history: history
  });
};

export const sendMessageToGemini = async (
  userMessage: string,
  attachment: Attachment | null,
  genMode: GenerationMode,
  astraMode: AstraMode,
  onStream: (text: string) => void,
  onMetadata: (metadata: GroundingMetadata) => void,
  history: Content[] = []
): Promise<string> => {

  if (!chatInstance || currentGenMode !== genMode) {
      initializeChat(genMode, astraMode, history);
  }

  let fullResponse = "";

  try {
    let result;

    if (attachment) {
       const { model, config } = getModelConfig(genMode, astraMode);
       const response = await ai.models.generateContentStream({
        model: model,
        contents: {
          parts: [
            { inlineData: { data: attachment.base64, mimeType: attachment.mimeType } },
            { text: userMessage }
          ]
        },
        config: config
       });
       result = response;
    } else {
       result = await chatInstance!.sendMessageStream({ message: userMessage });
    }

    for await (const chunk of result) {
      const c = chunk as GenerateContentResponse;
      const text = c.text;
      if (text) {
        fullResponse += text;
        onStream(fullResponse);
      }
      if (c.candidates?.[0]?.groundingMetadata) {
          onMetadata(c.candidates[0].groundingMetadata as GroundingMetadata);
      }
    }

  } catch (error) {
    console.error("Gemini API Error:", error);
    onStream("CONNECTION ERROR.");
    return "Error";
  }

  return fullResponse;
};

export const speakText = async (
    text: string, 
    astraMode: AstraMode = 'normal', 
    customProfile?: VoiceProfile,
    stop: boolean = false,
    onComplete?: () => void
) => {
    const requestId = ++currentTtsRequestId;

    if (ttsSource) {
        try { ttsSource.stop(); } catch (e) {}
        ttsSource = null;
    }

    if (stop || !text) {
        if (onComplete) onComplete();
        return;
    }

    if (!ttsAudioContext) {
        ttsAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }

    if (ttsAudioContext.state === 'suspended') {
        await ttsAudioContext.resume();
    }

    let voiceName = 'Kore';
    if (astraMode === 'roast') voiceName = 'Puck';
    if (astraMode === 'skull') voiceName = 'Fenrir';

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: { parts: [{ text: text }] },
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: {
                        prebuiltVoiceConfig: { voiceName }
                    }
                }
            },
        });

        if (requestId !== currentTtsRequestId) return;

        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

        if (base64Audio) {
            const audioBuffer = await decodeAudioData(base64Audio, ttsAudioContext);
            if (requestId !== currentTtsRequestId) return;

            const source = ttsAudioContext.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(ttsAudioContext.destination);

            source.onended = () => {
                if (requestId === currentTtsRequestId) {
                    ttsSource = null;
                    if (onComplete) onComplete();
                }
            };

            source.start();
            ttsSource = source;
        } else {
             if (onComplete) onComplete();
        }
    } catch (e) {
        console.error("TTS Failed", e);
        if (onComplete) onComplete();
    }
};

const decodeAudioData = async (base64: string, ctx: AudioContext): Promise<AudioBuffer> => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }

    const numChannels = 1;
    const sampleRate = 24000;

    try {
        const bufferCopy = bytes.buffer.slice(0);
        return await ctx.decodeAudioData(bufferCopy);
    } catch (e) {
        const dataInt16 = new Int16Array(bytes.buffer);
        const frameCount = dataInt16.length;
        const audioBuffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
        const channelData = audioBuffer.getChannelData(0);
        for (let i = 0; i < frameCount; i++) {
             channelData[i] = dataInt16[i] / 32768.0;
        }
        return audioBuffer;
    }
};

export const generateEditedImage = async (prompt: string, base64Image?: string, mimeType?: string): Promise<string | null> => {
  try {
    const parts: Part[] = [];
    if (base64Image && mimeType) {
      parts.push({ inlineData: { data: base64Image, mimeType: mimeType } });
    }
    parts.push({ text: prompt });

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts },
      config: { imageConfig: { aspectRatio: '1:1' } }
    });

    for (const candidate of response.candidates || []) {
        for (const part of candidate.content?.parts || []) {
            if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
        }
    }
    return null;
  } catch (e) {
    return null;
  }
};

export const runAstraDetection = async (attachment: Attachment, onStream: (text: string) => void): Promise<string> => {
  const prompt = `Perform forensic scan for AI generation artifacts. Output: [ANOMALIES_DETECTED], [FORENSIC_REPORT], [CONCLUSION] with VERDICT and CONFIDENCE_SCORE. Architect: Ayush Singh.`;
  let fullResponse = "";
  try {
    const response = await ai.models.generateContentStream({
        model: 'gemini-3-pro-preview',
        contents: {
            parts: [
                { inlineData: { data: attachment.base64, mimeType: attachment.mimeType } },
                { text: prompt }
            ]
        },
        config: { temperature: 0.1 }
    });
    for await (const chunk of response) {
        if (chunk.text) {
            fullResponse += chunk.text;
            onStream(fullResponse);
        }
    }
    return fullResponse;
  } catch (e) {
      return "Scan Failed";
  }
};

export class AstraLiveSession {
  private inputAudioContext: AudioContext | null = null;
  private outputAudioContext: AudioContext | null = null;
  private mediaStream: MediaStream | null = null;
  private processor: ScriptProcessorNode | null = null;
  private source: MediaStreamAudioSourceNode | null = null;
  private nextStartTime = 0;
  private astraMode: AstraMode;

  constructor(mode: AstraMode) {
    this.astraMode = mode;
  }

  async start(onClose: () => void) {
    this.inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    this.outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    const systemInstruction = getSystemPrompt(this.astraMode);
    let voiceName = 'Kore';
    if (this.astraMode === 'roast') voiceName = 'Puck';
    if (this.astraMode === 'skull') voiceName = 'Fenrir';

    try {
        const sessionPromise = ai.live.connect({
            model: 'gemini-2.5-flash-native-audio-preview-09-2025',
            config: {
                responseModalities: [Modality.AUDIO],
                systemInstruction: systemInstruction,
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName } } 
                }
            },
            callbacks: {
                onopen: async () => { this.startRecording(sessionPromise); },
                onmessage: async (message: LiveServerMessage) => {
                    const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (audioData) await this.playAudio(audioData);
                },
                onclose: () => { this.stop(); onClose(); },
                onerror: (err) => { this.stop(); onClose(); }
            }
        });
    } catch (err) {
        onClose();
    }
  }

  private async startRecording(sessionPromise: Promise<any>) {
      if (!this.inputAudioContext) return;
      this.mediaStream = await navigator.mediaDevices.getUserMedia({ audio: true });
      this.source = this.inputAudioContext.createMediaStreamSource(this.mediaStream);
      this.processor = this.inputAudioContext.createScriptProcessor(4096, 1, 1);
      this.processor.onaudioprocess = (e) => {
          const inputData = e.inputBuffer.getChannelData(0);
          const pcmData = this.convertFloat32ToInt16(inputData);
          const base64 = this.arrayBufferToBase64(pcmData.buffer);
          sessionPromise.then(session => {
              session.sendRealtimeInput({ media: { mimeType: 'audio/pcm;rate=16000', data: base64 } });
          });
      };
      this.source.connect(this.processor);
      this.processor.connect(this.inputAudioContext.destination);
  }

  private async playAudio(base64: string) {
      if (!this.outputAudioContext) return;
      const arrayBuffer = this.base64ToArrayBuffer(base64);
      const float32Data = this.convertInt16ToFloat32(new Int16Array(arrayBuffer));
      const audioBuffer = this.outputAudioContext.createBuffer(1, float32Data.length, 24000);
      audioBuffer.getChannelData(0).set(float32Data);
      const source = this.outputAudioContext.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(this.outputAudioContext.destination);
      const currentTime = this.outputAudioContext.currentTime;
      if (this.nextStartTime < currentTime) this.nextStartTime = currentTime;
      source.start(this.nextStartTime);
      this.nextStartTime += audioBuffer.duration;
  }

  stop() {
      this.processor?.disconnect();
      this.source?.disconnect();
      this.mediaStream?.getTracks().forEach(t => t.stop());
      this.inputAudioContext?.close();
      this.outputAudioContext?.close();
  }

  private convertFloat32ToInt16(float32: Float32Array) {
      const int16 = new Int16Array(float32.length);
      for (let i = 0; i < float32.length; i++) {
          int16[i] = Math.max(-1, Math.min(1, float32[i])) * 0x7FFF;
      }
      return int16;
  }

  private convertInt16ToFloat32(int16: Int16Array) {
      const float32 = new Float32Array(int16.length);
      for (let i = 0; i < int16.length; i++) {
          float32[i] = int16[i] / 0x7FFF;
      }
      return float32;
  }

  private arrayBufferToBase64(buffer: ArrayBuffer) {
      let binary = '';
      const bytes = new Uint8Array(buffer);
      for (let i = 0; i < bytes.byteLength; i++) {
          binary += String.fromCharCode(bytes[i]);
      }
      return btoa(binary);
  }

  private base64ToArrayBuffer(base64: string) {
      const binary = atob(base64);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) {
          bytes[i] = binary.charCodeAt(i);
      }
      return bytes.buffer;
  }
}

