const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

let chatInstance: Chat | null = null;
let currentGenMode: GenerationMode = 'CHAT';
let ttsAudioContext: AudioContext | null = null;
let ttsSource: AudioBufferSourceNode | null = null;
let currentTtsRequestId = 0;

const getSystemPrompt = () => {
    const now = new Date();
    const istTime = now.toLocaleString("en-IN", { timeZone: "Asia/Kolkata", dateStyle: "full", timeStyle: "medium" });
    const timeContext = `\n\n[SYNC]: ${istTime} | LOC: INDIA | ARCHITECT: AYUSH SINGH`;
    return ASTRA_SYSTEM_INSTRUCTION + timeContext;
};

const getModelConfig = (genMode: GenerationMode) => {
  const systemInstruction = getSystemPrompt();

  switch (genMode) {
    case 'DEEP_THINK':
      return {
        model: 'gemini-3-pro-preview',
        config: {
          systemInstruction,
          thinkingConfig: { thinkingBudget: 32768 }
        }
      };
    case 'WEB_INTEL':
      return {
        model: 'gemini-2.5-flash',
        config: {
          systemInstruction,
          tools: [{ googleSearch: {} } as Tool]
        }
      };
    case 'SPEED_RUN':
      return {
        model: 'gemini-2.5-flash',
        config: {
          systemInstruction,
          temperature: 0.7
        }
      };
    case 'ASTRA_CODER':
        return {
             model: 'gemini-3-pro-preview',
             config: { 
                 systemInstruction: "You are ASTRA CODER. Expert developer. Architect: Ayush Singh. Provide clean, production-ready code blocks.",
                 temperature: 0.2 
             }
        };
    case 'IMAGE_EDIT': 
        return {
            model: 'gemini-2.5-flash-image',
            config: { systemInstruction }
        };
    case 'ASTRA_DETECTION':
         return {
            model: 'gemini-3-pro-preview',
