import React, { useEffect, useRef } from 'react';
import { AstraMode } from '../types';

interface CyberBackgroundProps {
  mode: AstraMode;
  isProcessing?: boolean;
  pulseTrigger?: number;
}

export const CyberBackground: React.FC<CyberBackgroundProps> = ({ mode, isProcessing, pulseTrigger }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const pulseRef = useRef<number>(0);

  useEffect(() => {
    if (pulseTrigger) {
      pulseRef.current = 1.0; // Reset pulse intensity
    }
  }, [pulseTrigger]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let width = window.innerWidth;
    let height = window.innerHeight;

    const resize = () => {
      width = window.innerWidth;
      height = window.innerHeight;
      canvas.width = width;
      canvas.height = height;
    };

    window.addEventListener('resize', resize);
    resize();

    const lines: { y: number; speed: number; opacity: number; width: number }[] = [];
    const count = 4;
    for (let i = 0; i < count; i++) {
      lines.push({
        y: Math.random() * height,
        speed: 0.5 + Math.random() * 1.5,
        opacity: 0.05 + Math.random() * 0.1,
        width: 1 + Math.random() * 2
      });
    }

    const draw = () => {
      ctx.clearRect(0, 0, width, height);

      const baseColor = mode === 'skull' ? '239, 68, 68' : (mode === 'root' ? '34, 197, 94' : '0, 240, 255');

      // Draw Grid
      ctx.strokeStyle = `rgba(${baseColor}, ${0.03 + (pulseRef.current * 0.05)})`;
      ctx.lineWidth = 1;
      const gridSize = 60;

      ctx.beginPath();
      for (let x = 0; x < width; x += gridSize) {
        ctx.moveTo(x, 0);
        ctx.lineTo(x, height);
      }
      for (let y = 0; y < height; y += gridSize) {
        ctx.moveTo(0, y);
        ctx.lineTo(width, y);
      }
      ctx.stroke();

      // Pulse fade
      if (pulseRef.current > 0) {
        pulseRef.current *= 0.95;
      }

      // Draw Scan Lines
      lines.forEach(line => {
        const currentSpeed = isProcessing ? line.speed * 4 : line.speed;
        line.y += currentSpeed;
        if (line.y > height + 200) {
          line.y = -200;
          line.speed = 0.5 + Math.random() * 1.5;
        }

        const gradient = ctx.createLinearGradient(0, line.y, 0, line.y + 200);
        const alpha = (line.opacity + (pulseRef.current * 0.2)) * (isProcessing ? 2 : 1);

        gradient.addColorStop(0, 'transparent');
        gradient.addColorStop(0.5, `rgba(${baseColor}, ${alpha})`);
        gradient.addColorStop(1, 'transparent');

        ctx.fillStyle = gradient;
        ctx.fillRect(0, line.y, width, 200);
      });

      animationFrameId = requestAnimationFrame(draw);
    };

    draw();
    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, [mode, isProcessing]);

  return (
    <canvas 
      ref={canvasRef} 
      className="fixed inset-0 z-0 pointer-events-none opacity-50"
      style={{ mixBlendMode: 'screen' }}
    />
  );
};

